// ─── Radar chart SVG (inline) ───────────────────────────────────────────────

function generateRadarSVG(dimensions) {
  const W = 400, H = 400, CX = 200, CY = 210, R = 140, N = 5;
  const GRIDS = [20, 40, 60, 80, 100];

  const scores = dimensions.map(d => d.status === 'answered' ? d.adjScore : 0);

  function polarToXY(angle, radius) {
    const rad = (angle - 90) * (Math.PI / 180);
    return { x: CX + radius * Math.cos(rad), y: CY + radius * Math.sin(rad) };
  }
  function axisAngle(i) { return (i / N) * 360; }
  function fmt(n) { return n.toFixed(1); }

  // Grid polygons
  const grids = GRIDS.map(pct => {
    const pts = Array.from({ length: N }, (_, i) => {
      const p = polarToXY(axisAngle(i), (pct / 100) * R);
      return `${fmt(p.x)},${fmt(p.y)}`;
    }).join(' ');
    return `<polygon points="${pts}" fill="none" stroke="#E2E8F0" stroke-width="${pct === 100 ? 1.5 : 0.8}" ${pct < 100 ? 'stroke-dasharray="4,4"' : ''}/>`;
  }).join('\n');

  // Grid labels
  const gridLabels = GRIDS.map(pct => {
    const p = polarToXY(0, (pct / 100) * R);
    return `<text x="${fmt(p.x + 4)}" y="${fmt(p.y - 2)}" font-size="9" fill="#94A3B8" font-family="system-ui,sans-serif">${pct}</text>`;
  }).join('\n');

  // Axes
  const axes = Array.from({ length: N }, (_, i) => {
    const tip = polarToXY(axisAngle(i), R);
    return `<line x1="${CX}" y1="${CY}" x2="${fmt(tip.x)}" y2="${fmt(tip.y)}" stroke="#CBD5E1" stroke-width="1"/>`;
  }).join('\n');

  // Score polygon
  const scorePts = scores.map((s, i) => {
    const p = polarToXY(axisAngle(i), (s / 100) * R);
    return `${fmt(p.x)},${fmt(p.y)}`;
  }).join(' ');

  // Score dots
  const dots = scores.map((s, i) => {
    const p = polarToXY(axisAngle(i), (s / 100) * R);
    let color = '#EF4444';
    if (s >= 90) color = '#10B981';
    else if (s >= 75) color = '#3B82F6';
    else if (s >= 60) color = '#F59E0B';
    return `<circle cx="${fmt(p.x)}" cy="${fmt(p.y)}" r="5" fill="${color}" stroke="white" stroke-width="2"/>`;
  }).join('\n');

  // Labels
  const labels = dimensions.map((d, i) => {
    const angle = axisAngle(i);
    const lp = polarToXY(angle, R + 28);
    let anchor = 'middle';
    if (angle > 10 && angle < 170) anchor = 'start';
    else if (angle > 190 && angle < 350) anchor = 'end';
    let dy = 0;
    if (angle < 30 || angle > 330) dy = -4;
    else if (angle > 150 && angle < 210) dy = 12;

    const s = scores[i];
    let sColor = '#EF4444';
    if (s >= 90) sColor = '#10B981';
    else if (s >= 75) sColor = '#3B82F6';
    else if (s >= 60) sColor = '#F59E0B';

    const name = isZH ? (DIM_NAMES_ZH[d.id] || d.name) : d.name;
    return `<text x="${fmt(lp.x)}" y="${fmt(lp.y + dy)}" text-anchor="${anchor}" font-size="11" font-weight="600" fill="#1E293B" font-family="system-ui,sans-serif">${d.id} ${name}</text>
<text x="${fmt(lp.x)}" y="${fmt(lp.y + dy + 15)}" text-anchor="${anchor}" font-size="14" font-weight="700" fill="${sColor}" font-family="system-ui,sans-serif">${s.toFixed(1)}</text>`;
  }).join('\n');

  // Overall badge
  const ov = data.overall.adj.toFixed(1);
  const ovLabel = isZH ? '综合' : 'OVERALL';

  return `<svg width="${W}" height="${H}" viewBox="0 0 ${W} ${H}" xmlns="http://www.w3.org/2000/svg">
  <rect width="${W}" height="${H}" fill="white" rx="12"/>
  ${grids}
  ${gridLabels}
  ${axes}
  <circle cx="${CX}" cy="${CY}" r="3" fill="#94A3B8" opacity="0.4"/>
  <polygon points="${scorePts}" fill="#3B82F6" fill-opacity="0.15" stroke="#2563EB" stroke-width="2" stroke-linejoin="round"/>
  ${dots}
  ${labels}
  <rect x="${CX - 32}" y="${CY - 16}" width="64" height="32" rx="8" fill="white" stroke="#E2E8F0" stroke-width="1.5"/>
  <text x="${CX}" y="${CY - 2}" text-anchor="middle" font-size="8" fill="#64748B" font-family="system-ui,sans-serif">${ovLabel}</text>
  <text x="${CX}" y="${CY + 11}" text-anchor="middle" font-size="14" font-weight="700" fill="#0F172A" font-family="system-ui,sans-serif">${ov}</text>
</svg>`;
}

// ─── Capability analysis ────────────────────────────────────────────────────

function generateAnalysis(dimensions) {
  const answered = dimensions.filter(d => d.status === 'answered');
  if (answered.length === 0) return isZH ? '<p>所有维度均已跳过，无法生成分析。</p>' : '<p>All dimensions skipped, cannot generate analysis.</p>';

  const sorted = [...answered].sort((a, b) => b.adjScore - a.adjScore);
  const strongest = sorted[0];
  const weakest = sorted[sorted.length - 1];

  const analyses = {
    D1: {
      high: isZH ? '展现出优秀的多步推理能力，能够跨领域建立逻辑链条，因果分析清晰。' : 'Demonstrates excellent multi-step reasoning ability, capable of building logical chains across domains with clear causal analysis.',
      mid: isZH ? '推理能力中等，能处理基本逻辑推导，但在多层嵌套推理和跨领域类比方面有提升空间。' : 'Moderate reasoning ability, handles basic logical deduction but has room for improvement in multi-layer nested reasoning and cross-domain analogies.',
      low: isZH ? '推理链较短，容易在复杂推理中丢失关键步骤。建议通过结构化思维训练提升。' : 'Reasoning chains are short, tends to lose critical steps in complex reasoning. Structured thinking training recommended.',
    },
    D2: {
      high: isZH ? '信息检索能力出色，能准确定位信息源，综合多来源数据并进行有效验证。' : 'Excellent information retrieval, accurately locates sources, synthesizes multi-source data with effective verification.',
      mid: isZH ? '检索能力一般，能找到基本信息但深度和来源多样性不足。建议提升搜索策略。' : 'Average retrieval capability, finds basic information but lacks depth and source diversity. Improve search strategies.',
      low: isZH ? '信息检索薄弱，难以有效利用搜索工具获取准确信息。需要重点加强。' : 'Weak information retrieval, struggles to effectively use search tools for accurate information. Focus area for improvement.',
    },
    D3: {
      high: isZH ? '内容创作能力强，输出结构清晰、表达精准，能适应不同体裁和受众需求。' : 'Strong content creation, clear structure, precise expression, adapts to different genres and audience needs.',
      mid: isZH ? '创作能力中等，基本结构完整但缺乏亮点。建议提升文本的层次感和说服力。' : 'Moderate creation ability, basic structure intact but lacks highlights. Improve text layering and persuasiveness.',
      low: isZH ? '创作输出质量较低，结构松散、表达不够精炼。建议加强写作练习。' : 'Low quality creative output, loose structure, expression not refined enough. Writing practice recommended.',
    },
    D4: {
      high: isZH ? '执行与构建能力优秀，代码质量高，能独立完成复杂构建任务。' : 'Excellent execution and building capability, high code quality, independently completes complex building tasks.',
      mid: isZH ? '执行能力中等，能完成基本构建任务但在复杂场景下容易出错。' : 'Moderate execution capability, completes basic tasks but error-prone in complex scenarios.',
      low: isZH ? '执行构建能力不足，需要更多实践来提升代码编写和调试能力。' : 'Insufficient execution capability, needs more practice to improve coding and debugging skills.',
    },
    D5: {
      high: isZH ? '工具编排能力出色，能高效组合多个工具解决复杂问题，流程设计合理。' : 'Excellent tool orchestration, efficiently combines multiple tools for complex problems with well-designed workflows.',
      mid: isZH ? '工具编排能力一般，能使用基本工具但多工具协同和流程优化有待提升。' : 'Average tool orchestration, uses basic tools but multi-tool coordination and workflow optimization need improvement.',
      low: isZH ? '工具编排薄弱，难以有效组合工具完成任务。建议练习多工具协同场景。' : 'Weak tool orchestration, struggles to effectively combine tools. Practice multi-tool coordination scenarios.',
    },
  };

  let html = '';

  // Per-dimension analysis cards
  answered.forEach(d => {
    const analysis = analyses[d.id] || analyses.D1;
    let desc;
    if (d.adjScore >= 80) desc = analysis.high;
    else if (d.adjScore >= 60) desc = analysis.mid;
    else desc = analysis.low;

    const name = isZH ? (DIM_NAMES_ZH[d.id] || d.name) : d.name;
    const diff = isZH ? (DIFF_ZH[d.difficulty] || d.difficulty) : d.difficulty;
    const scoreColor = d.adjScore >= 80 ? '#10B981' : d.adjScore >= 60 ? '#F59E0B' : '#EF4444';

    html += `
    <div class="analysis-card">
      <div class="analysis-header">
        <span class="dim-badge">${d.id}</span>
        <span class="dim-name">${name}</span>
        <span class="dim-diff">${diff} ×${d.multiplier}</span>
        <span class="dim-score" style="color:${scoreColor}">${d.adjScore.toFixed(1)}</span>
      </div>
      <div class="analysis-bar-bg">
        <div class="analysis-bar" style="width:${Math.min(100, d.adjScore)}%;background:${scoreColor}"></div>
      </div>
      <p class="analysis-desc">${desc}</p>
    </div>`;
  });

  // Summary
  const sName = isZH ? (DIM_NAMES_ZH[strongest.id] || strongest.name) : strongest.name;
  const wName = isZH ? (DIM_NAMES_ZH[weakest.id] || weakest.name) : weakest.name;

  html += `
  <div class="analysis-summary">
    <div class="summary-item strongest">
      <div class="summary-label">${t.strongest}</div>
      <div class="summary-value">${strongest.id} ${sName} — ${strongest.adjScore.toFixed(1)}</div>
    </div>
    <div class="summary-item weakest">
      <div class="summary-label">${t.weakest}</div>
      <div class="summary-value">${weakest.id} ${wName} — ${weakest.adjScore.toFixed(1)}</div>
    </div>
  </div>`;

  return html;
}

// ─── Question detail cards ──────────────────────────────────────────────────

function generateQuestionCards(dimensions) {
  return dimensions.map((d, idx) => {
    const name = isZH ? (DIM_NAMES_ZH[d.id] || d.name) : d.name;
    const diff = isZH ? (DIFF_ZH[d.difficulty] || d.difficulty) : d.difficulty;
    const statusText = d.status === 'answered' ? t.answered : t.skipped;

    if (d.status === 'skipped') {
      return `
      <div class="question-card skipped">
        <div class="q-header">
          <span class="q-num">Q${idx + 1}</span>
          <span class="q-dim">${d.id} ${name}</span>
          <span class="q-status skip-badge">${statusText}</span>
        </div>
        <p class="skip-reason">${isZH ? '原因' : 'Reason'}: ${d.skipReason || 'Required capability not available'}</p>
      </div>`;
    }

    const criteriaRows = (d.criteria || []).map(c => `
      <tr>
        <td>${c.name}</td>
        <td>${(c.weight * 100).toFixed(0)}%</td>
        <td><span class="score-pill ${c.score >= 4 ? 'high' : c.score >= 3 ? 'mid' : 'low'}">${c.score}/5</span></td>
        <td class="justification">${c.justification || ''}</td>
      </tr>`).join('');

    const confLabel = isZH
      ? { high: '高', medium: '中', low: '低' }[d.confidence] || d.confidence
      : d.confidence;

    return `
    <div class="question-card">
      <div class="q-header">
        <span class="q-num">Q${idx + 1}</span>
        <span class="q-dim">${d.id} ${name}</span>
        <span class="q-diff">${diff} ×${d.multiplier}</span>
        <span class="q-score-badge" style="background:${d.adjScore >= 80 ? '#DCFCE7' : d.adjScore >= 60 ? '#FEF3C7' : '#FEE2E2'};color:${d.adjScore >= 80 ? '#166534' : d.adjScore >= 60 ? '#92400E' : '#991B1B'}">${d.adjScore.toFixed(1)}</span>
        <span class="q-status">${statusText}</span>
      </div>

      <details class="q-details">
        <summary>${t.question}</summary>
        <div class="q-text">${escapeHtml(d.question || '')}</div>
      </details>

      <details class="q-details" open>
        <summary>${t.answer} (${t.confidence}: ${confLabel})</summary>
        <div class="q-answer">${escapeHtml(d.answer || '')}</div>
      </details>

      <details class="q-details">
        <summary>${t.scoring} — ${t.raw}: ${d.rawScore} → ${t.adjusted}: ${d.adjScore.toFixed(1)}</summary>
        <table class="criteria-table">
          <thead><tr><th>${t.criterion}</th><th>${t.weight}</th><th>${t.score}</th><th>${t.justification}</th></tr></thead>
          <tbody>${criteriaRows}</tbody>
        </table>
      </details>
    </div>`;
  }).join('\n');
}

function escapeHtml(str) {
  return str.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
    .replace(/\n/g, '<br>');
}

// ─── Level display ──────────────────────────────────────────────────────────

function levelDisplay(level) {
  const color = LEVEL_COLORS[level] || '#64748B';
  const label = isZH ? (LEVEL_ZH[level] || level) : level;
  return `<span class="level-badge" style="background:${color}">${label}</span>`;
}

// ─── Build HTML ─────────────────────────────────────────────────────────────

const dims = data.dimensions || [];
const overall = data.overall || { raw: 0, adj: 0, level: 'Beginner' };
const modeDisplay = data.mode === 'full' ? t.fullMode : t.dimMode;

const dimTableRows = dims.map(d => {
